                if(not isinstance(name_list,list) or not isinstance(weight_list,list)):
                    raise TypeError("name_list and weight_list must be lists!")
                elif(not all([(mathLib.isRealNum(w) and w>0) for w in weight_list])):
                    raise TypeError("weight_list must contain only positive real numbers!")
